    dealCadastre: function (cadaNoStr) {
      let isCadastre = false
      let tmp1 = ''
      let tmp2 = ''
      let obj = {'isCadastre': false }

      const regex = /[一二三四五六七八九十○]{1,3}(│|\||ノ|番?之)[一二三四五六七八九十○]{1,3}/g
      let m;
      while ((m = regex.exec(cadaNoStr)) !== null) {
          // This is necessary to avoid infinite loops with zero-width matches
          if (m.index === regex.lastIndex) {
              regex.lastIndex++
          }
          tmp1 = m[0]
          tmp2 = this.text2Number(m[0])
          isCadastre = true
      }

      if (!isCadastre) {
        obj.isCadastre = false
        return obj
      }

      cadaNoStr = cadaNoStr.replace(tmp1, tmp2).replace(/\s/g, '')

      if (cadaNoStr.indexOf("土名") > -1) {
        const regex = /([\u4e00-\u9fa5]+堡)([\u4e00-\u9fa5]+庄)土名([\u4e00-\u9fa5]{2,4})(\d+)-(\d+)/g
        let m
