          if (m.index === regex.lastIndex) {
              regex.lastIndex++
          }
          //console.log(m[0]);
          obj.isCadastre = true
          obj.b = m[1]
          obj.z = m[2]
          obj.d = m[3]
          obj.mn = m[4]
          obj.sn = m[5]
        }
      } else {
        const regex = /([\u4e00-\u9fa5]+堡)([\u4e00-\u9fa5]+庄)(\d+)-(\d+)/g
        let m
        while ((m = regex.exec(cadaNoStr)) !== null) {
          // This is necessary to avoid infinite loops with zero-width matches
          if (m.index === regex.lastIndex) {
              regex.lastIndex++
          }
          //console.log(m[0]);
          obj.isCadastre = true
          obj.b = m[1]
          obj.z = m[2]
          obj.d = ''
          obj.mn = m[3]
          obj.sn = m[4]
        }
      }
      return obj
    }
