  created: async function () {
  const fetchJSON = async function (url) { 
    try {
      return  await (await fetch(url)).json()
    } catch (e) {
      return JSON.parse((await(await fetch(url)).text()).replace(/\n/gm, ' '))
    }
  };
  
  const n = new URLSearchParams(window.location.search).get('n');
  if (!n) return;

  const KP = await fetchJSON('https://dhumanities.github.io/markus/js/kPlaceLatLon.json');
  const cada = this.dealCadastre(n);

  const processPlacenames = async (url, filter = () => true) => {
    try {
      const { placenames = [] } = await fetchJSON(url);
      this.allJson = this.allJson.concat(placenames.filter(filter));
    } catch (e) {
      console.error(e);
    }
  };

  if (cada.isCadastre) {
    const url = `https://docusky.org.tw/DocuSky/docutools/geocode/twcada.php?t=&b=${encodeURIComponent(cada.b)}&z=${encodeURIComponent(cada.z)}&d=${encodeURIComponent(cada.d)}&n=${cada.mn}`;
    await processPlacenames(url);
  } else if (n.includes("twcada_")) {
    await processPlacenames(`https://docusky.org.tw/DocuSky/docutools/geocode/twcada.php?n=${n}`);
  } else {
    await processPlacenames(`https://docusky.org.tw/DocuSky/docutools/geocode/tw.php?n=${encodeURIComponent(n)}`);

    if (n.startsWith("hvd_")) {
      try {
        const harvardUrl = `https://chgis.hudci.org/tgaz/placename/json/${n}`;
        let { spellings } = await fetchJSON(harvardUrl);
        const placename = spellings[0]["written form"];
        await processPlacenames(`https://chgis.hudci.org/tgaz/placename?fmt=json&n=${placename}`, x => x.sys_id === n);
      } catch (e) {
        console.error(e);
      }
    } else {
      await processPlacenames(`https://chgis.hudci.org/tgaz/placename?fmt=json&n=${n}`);
    }

    const KPlaces = decodeURIComponent(n).split("|");
    const KPlaceNames = KP.filter(x =>
      KPlaces.some(y => x[2].includes(y) || `koreanPlace_${x[0]}` === y)
    ).sort((a, b) => a[2].length - b[2].length);

    this.allJson = this.allJson.concat(KPlaceNames.map(x => ({
      sys_id: `koreanPlace_${x[0]}`,
      name: `${x[2]}${x[3] ? `(${x[3]})` : ''}`,
      transcription: "",
      years: x[4] || '',
      "parent sys_id": "",
      "parent name": "",
      "feature type": "POINT",
      "xy coordinates": x[6] ? `${x[6]},${x[7]}` : '',
      "data source": ""
    })));
  }
